/**
 * Pure validation functions for order operations.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that an order has at least one item.
 * Throws if the items array is empty.
 */
export function validateOrderHasItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing if it is not allowed.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Pure validation functions for user operations.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken.
 * Takes the result of a findByEmail lookup as input.
 * Throws if a user with that email already exists.
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not already in use by another user.
 * Used during updates where the current user's own email should be allowed.
 * Throws if a different user holds the email.
 */
export function validateEmailNotInUse(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Validate that a user exists.
 * Takes the result of a findById lookup as input.
 * Throws if the user is not found.
 */
export function validateUserExists(
  id: string,
  user: User | undefined,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${id}`);
  }
}

/**
 * Pure validation functions for notification preferences.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';

/**
 * Determine whether an email notification of the given type should be
 * sent based on the user's preferences.
 *
 * Returns true if:
 *  - No preferences exist (default: send all)
 *  - Email is enabled AND the category is subscribed AND frequency is not 'none'
 */
export function shouldSendNotification(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences stored — default to sending
  if (!preferences) {
    return true;
  }

  if (!preferences.email.enabled) {
    return false;
  }

  if (preferences.email.frequency === 'none') {
    return false;
  }

  return preferences.email.subscribedCategories.includes(notificationType);
}

