    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateEmailNotInUse,
  validateUserExists,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user validators', () => {
  describe('validateEmailNotTaken', () => {
    it('should throw when a user with that email exists', () => {
      expect(() =>
        validateEmailNotTaken('alice@example.com', makeUser()),
      ).toThrow('User with email alice@example.com already exists');
    });

    it('should not throw when no user has that email', () => {
      expect(() =>
        validateEmailNotTaken('alice@example.com', undefined),
      ).not.toThrow();
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should throw when the email is in use', () => {
      expect(() =>
        validateEmailNotInUse('alice@example.com', makeUser()),
      ).toThrow('Email alice@example.com is already in use');
    });

    it('should not throw when the email is available', () => {
      expect(() =>
        validateEmailNotInUse('alice@example.com', undefined),
      ).not.toThrow();
    });
  });

  describe('validateUserExists', () => {
    it('should throw when user is not found', () => {
      expect(() => validateUserExists('user-9999', undefined)).toThrow(
        'User not found: user-9999',
      );
    });

    it('should not throw when user exists', () => {
      expect(() => validateUserExists('user-0001', makeUser())).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

const makePrefs = (
  overrides: Partial<UserPreferences['email']> = {},
): UserPreferences => ({
  id: 'pref-0001',
  userId: 'user-0001',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: ['order:confirmation', 'order:status-update'],
    ...overrides,
  },
  createdAt: new Date(),
  updatedAt: new Date(),
});

describe('preferences validators', () => {
  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist', () => {
      expect(shouldSendNotification(undefined, 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      expect(
        shouldSendNotification(makePrefs(), 'order:confirmation'),
      ).toBe(true);
    });

    it('should return false when email is disabled', () => {
      expect(
        shouldSendNotification(makePrefs({ enabled: false }), 'order:confirmation'),
      ).toBe(false);
    });

    it('should return false when frequency is none', () => {
      expect(
        shouldSendNotification(makePrefs({ frequency: 'none' }), 'order:confirmation'),
      ).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      expect(
        shouldSendNotification(makePrefs(), 'user:welcome'),
      ).toBe(false);
    });

    it('should return true for subscribed category with daily frequency', () => {
      expect(
        shouldSendNotification(
          makePrefs({ frequency: 'daily' }),
          'order:confirmation',
        ),
      ).toBe(true);
    });
  });
});
